{{#ifeq: 0 | {{#ifexist: ISO 639:{{#invoke:String|sub|{{BASEPAGENAME}}|6}}|0|1}}
| [[Category:Lang-x templates|{{#invoke:String|match|{{FULLPAGENAME}}|Template:Lang%-([a-zA-Z0-9%-]+)$|nomatch=}}]]
| {{#if: {{#invoke:Lang/documentor tool|uses_module|template={{ROOTPAGENAME}}}}
| [[Category:Lang-x templates|{{#invoke:String|match|{{FULLPAGENAME}}|Template:Lang%-([a-zA-Z0-9%-]+)$|nomatch=}}]]
| [[Category:Lang-x templates with other than ISO 639]]
}}}}
}}</includeonly><noinclude>
